{
  "family": "Ritter Reaction",
  "candidate": {
    "substrate_smiles": [
      "CC(C)(C)O",
      "CC#N"
    ],
    "product_smiles": [
      "CC(=O)NC(C)(C)C"
    ],
    "optional_reagent_smiles": [
      "O=S(=O)(O)O"
    ],
    "rationale": "This reaction is a classic textbook example of the Ritter reaction, demonstrating the formation of a stable tert-butyl carbocation from tert-butanol under strong acid (sulfuric acid) catalysis. The carbocation is then trapped by acetonitrile, which acts as the nucleophile. Subsequent hydrolysis of the resulting nitrilium ion intermediate yields N-tert-butylacetamide. All reactants and products are simple, acyclic, and lack complex functional groups, making this a clear and unambiguous representation of the core transformation.",
    "collision_avoidance_note": "The use of simple aliphatic substrates (tert-butanol and acetonitrile) avoids motifs common in other named reactions. Specifically, it avoids arenes (Friedel-Crafts, etc.), carbonyls (aldol, Claisen, etc.), and other potentially reactive functional groups that could cause collisions with different reaction families. The transformation is clearly an amidation via a carbocation-nitrile coupling, which is characteristic of the Ritter reaction."
  }
}
